			s--;
			fa(i, 0, n - 1) {
				if (s & (1 << i))p[i] = 1;
				else p[i] = 0;
			}
			fa(i, 1, n - 1) {
				int u, v; cin >> u >> v;
				u--, v--;
				if (p[u] == p[v]) {
					cout << u + 1 << ' ' << v + 1 << endl;
					cout.flush();
				}
				else {
					cout << v + 1 << ' ' << u + 1 << endl;
					cout.flush();
				}
			}
		}
	}
	else {
		while (t--) {
			int n; cin >> n;
			var g = vector<vector<pii>>(n);
			fa(i, 1, n - 1) {
				int u, v; cin >> u >> v;
				u--, v--;
				if (u < v) {
					g[u].pb({ v,0 });
					g[v].pb({ u,0 });
				}
				else {
					g[u].pb({ v,1 });
					g[v].pb({ u,1 });
				}
			}
			var Q = queue<int>();
			var res = vector<int>(n, -1);
			Q.push(n - 1); res[n - 1] = 0;
			while (Q.size()) {
				int now = Q.front();
				Q.pop();
				for (const var& [to, w] : g[now]) {
					if (res[to] != -1)continue;
					if (w)res[to] = (res[now] ^ 1);
					else res[to] = res[now];
					Q.push(to);
				}
			}
			int ans = 0;
			fa(i, 0, n - 1)if (res[i])ans += (1 << i);
			cout << ans + 1 << endl;
			cout.flush();
		}
	}
	return;
}
